    ```typescript
    class Node {
        key: string;
        value: number;
        prev: Node | null;
        next: Node | null;
        constructor(key: string, value: number) {
            this.key = key;
            this.value = value;
            this.prev = null;
            this.next = null;
        }
    }

    class LRUCache {
        capacity: number;
        size: number;
        map: Map<string, Node>;
        head: Node | null;
        tail: Node | null;

        constructor(capacity: number) {
            this.capacity = capacity;
            this.size = 0;
            this.map = new Map();
            this.head = null;
            this.tail = null;
        }

        private removeNode(node: Node) {
            if (node.prev) node.prev.next = node.next;
            else this.head = node.next;
            if (node.next) node.next.prev = node.prev;
            else this.tail = node.prev;
            node.prev = null;
            node.next = null;
        }

        private addToFront(node: Node) {
            node.next = this.head;
            node.prev = null;
            if (this.head) this.head.prev = node;
            this.head = node;
            if (!this.tail) this.tail = node;
        }

        put(key: string, value: number) {
            if (this.map.has(key)) {
                const node = this.map.get(key)!;
                node.value = value;
                this.removeNode(node);
                this.addToFront(node);
            } else {
                if (this.size === this.capacity) {
                    if (this.tail) {
                        const lru = this.tail;
                        this.removeNode(lru);
                        this.map.delete(lru.key);
                        this.size--;
                    }
                }
                const newNode = new Node(key, value);
                this.map.set(key, newNode);
                this.addToFront(newNode);
                this.size++;
            }
        }

        get(key: string): number {
            if (this.map.has(key)) {
                const node = this.map.get(key)!;
                this.removeNode(node);
                this.addToFront(node);
                return node.value;
            }
            return -1;
        }

        del(key: string) {
            if (this.map.has(key)) {
                const node = this.map.get(key)!;
                this.removeNode(node);
                this.map.delete(key);
                this.size--;
            }
        }

        getKeys() {
            const keys: string[] = [];
             let curr = this.head;
             while (curr) {
                 keys.push(curr.key);
                 curr = curr.next;
             }
            return keys;
        }
    }
    ```

